import streamlit as st

st.title('Les bases')

st.subheader("Fonctions d'affichage:")

st.write('st.write')
st.markdown('st.markdown')
st.text('st.text')
st.info('st.info')
st.success('st.success')
st.error('st.error')
st.warning('st.warning')
st.header('st.header')

st.subheader('Les inputs:')

st.number_input('Entrez un nombre: ', min_value=1)
st.text_input('Entrez un texte:')
st.date_input('Choisir une date:')
st.time_input('Heure:')
st.camera_input('Caméra:')

st.subheader('Colonnes:')

col1,col2,col3 = st.columns(3)

col1.write('col1')
col2.write('col2')
col3.write('col3')

st.subheader('File upload:')

photo = st.file_uploader('Choisir une image:', ['.png','.jpg','.jpeg'])

if photo is not None:
    st.write(f'Name: {photo.name}')
    st.image(photo.getvalue(),width=200)

st.subheader('Bouton:')

clic = st.button('Cliquez ici:', type='primary')

if clic == True:
    st.write('Vous avez cliquer')

st.subheader('Checkbox (cases à cocher)')

cocher = st.checkbox('ADMIN', key='ADMIN')

if cocher == True:
    st.write(cocher)

st.subheader('Radio Button:')
radio = st.radio('profil', ['Consultant', 'Manager','Développeur'], key='profil', horizontal=True)

st.write(radio)

st.subheader('Multiselection (dropdown list)')

couleurs = st.multiselect(
    'Choisir couleurs',
    ['Rouge', 'Jaune', 'Noir', 'Blanc'],
    ['Noir', 'Blanc']
)

st.write('Vous avez sélectionné:', couleurs)

st.subheader('Liste Slider:')

age = st.slider('Votre âge ?', 0,100,25)
st.write("Vous avez",age,'ans')

st.subheader('Tabs (Onglets)')

tab1,tab2,tab3 = st.tabs(['Chat', 'Chien', 'Lion'])

with tab1:
    st.header('Chat')
    st.image('data:image/jpeg;base64,')

with tab2:
    st.header('Chien')
    st.image('data:image/jpeg;base64,')

with tab3:
    st.header('Lion')
    st.image('data:image/jpeg;base64,')

# sidebar: barre de navigation de gauche
with st.sidebar:
    st.radio(
        "Choisir une méthode d'envoi",
        ("Standard (7-15) jours", "Express (2-5) jours")
    )


st.toast('Fini')
st.balloons()
st.snow()
                                                                                                                                                                                                                                                                                                                                                                               